class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id', '')
        self.event_type = data.get('event_type', '')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account', '')
        self.receiver_account = data.get('receiver_account', '')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (
            f"TransactionEvent(id={self.transaction_id}, type={self.event_type}, "
            f"amount={self.amount} {self.currency}, status={self.status})"
        )


class TransactionResult:
    """Result of processing a transaction event."""

    def __init__(self, transaction_id: str, success: bool, message: str = '',
                 data: Optional[Dict] = None):
        self.transaction_id = transaction_id
        self.success = success
        self.message = message
        self.data = data or {}
        self.processed_at = datetime.utcnow().isoformat()

    def __repr__(self):
        status = "SUCCESS" if self.success else "FAILED"
        return f"TransactionResult({self.transaction_id}: {status} - {self.message})"


class FraudDetectionService:
    """Simple fraud detection service."""

    SUSPICIOUS_AMOUNT_THRESHOLD = 10000.0
    BLOCKED_ACCOUNTS = {'BLOCKED001', 'BLOCKED002', 'SUSPICIOUS999'}

    @classmethod
    def check_transaction(cls, event: TransactionEvent) -> Dict[str, Any]:
        risks = []
        risk_score = 0.0

        if event.amount > cls.SUSPICIOUS_AMOUNT_THRESHOLD:
            risks.append(f"High amount: {event.amount} {event.currency}")
            risk_score += 0.4

        if event.sender_account in cls.BLOCKED_ACCOUNTS:
            risks.append(f"Blocked sender account: {event.sender_account}")
            risk_score += 0.8

        if event.receiver_account in cls.BLOCKED_ACCOUNTS:
            risks.append(f"Blocked receiver account: {event.receiver_account}")
            risk_score += 0.8

        if event.sender_account == event.receiver_account:
            risks.append("Self-transfer detected")
            risk_score += 0.3

        risk_score = min(risk_score, 1.0)

        return {
            'is_fraudulent': risk_score >= 0.7,
            'risk_score': risk_score,
            'risks': risks
        }


class MessageHandlerRegistry:
    """Registry for dynamically registering and executing message handlers."""

    def __init__(self):
        self._handlers: Dict[str, list[Callable]] = {}
        self._pre_processors: list[Callable] = []
        self._post_processors: list[Callable] = []

    def register_handler(self, event_type: str, handler: Callable):
        """Register a handler for a specific event type."""
        if event_type not in self._handlers:
            self._handlers[event_type] = []
        self._handlers[event_type].append(handler)
        logger.info(f"Registered handler '{handler.__name__}' for event type '{event_type}'")

    def register_pre_processor(self, processor: Callable):
        """Register a pre-processor that runs before handlers."""
        self._pre_processors.append(processor)

    def register_post_processor(self, processor: Callable):
        """Register a post-processor that runs after handlers."""
        self._post_processors.append(processor)

    def get_handlers(self, event_type: str) -> list[Callable]:
        """Get all handlers for a given event type."""
        handlers = self._handlers.get(event_type, [])
        default_handlers = self._handlers.get('*', [])
        return handlers + default_handlers

    def execute(self, event: TransactionEvent) -> list[TransactionResult]:
        """Execute all registered handlers for the event."""
        results = []

        # Run pre-processors
        for pre_proc in self._pre_processors:
            try:
                pre_proc(event)
            except Exception as e:
                logger.error(f"Pre-processor '{pre_proc.__name__}' failed: {e}")

        handlers = self.get_handlers(event.event_type)

        if not handlers:
            logger.warning(f"No handlers registered for event type: {event.event_type}")
            results.append(TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message=f"No handler for event type: {event.event_type}"
            ))
            return results

        for handler in handlers:
            try:
                result = handler(event)
                if isinstance(result, TransactionResult):
                    results.append(result)
                else:
                    results.append(TransactionResult(
                        transaction_id=event.transaction_id,
                        success=True,
                        message=f"Handler '{handler.__name__}' completed",
                        data={'result': result}
                    ))
            except Exception as e:
                logger.error(f"Handler '{handler.__name__}' failed for "
                             f"transaction {event.transaction_id}: {e}")
                results.append(TransactionResult(
                    transaction_id=event.transaction_id,
                    success=False,
                    message=f"Handler '{handler.__name__}' error: {str(e)}"
                ))

        # Run post-processors
        for post_proc in self._post_processors:
            try:
                post_proc(event, results)
            except Exception as e:
                logger.error(f"Post-processor '{post_proc.__name__}' failed: {e}")

        return results


